def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        complexity_factor = 1.0
        if ratio < 0.05:
            for a in range(1, 12):
                temp = np.exp(-ratio * a**1.1) * (a ** 3.1)
                if a % 4 == 0:
                    temp *= 0.87
                elif a % 2 == 0:
                    temp *= 1.02
                else:
                    temp *= 1.07
                score += temp
            if (capacity + item) % 4 == 0 or (capacity - item) % 7 == 0:
                score *= 0.83
            if score > 12:
                score /= 3.7
            if capacity > 150:
                score /= (np.log1p(capacity) + 1.5)
        elif 0.05 <= ratio < 0.25:
            prod = 1
            for n in range(1, int(capacity) + 3):
                val = ratio + n / (n**0.8 + 1)
                prod *= val
                if prod > 2e6:
                    prod = np.log1p(prod) * 1.8
                    break
            mod_val = int(prod * 1.1) % 400
            score += np.sqrt(ratio * mod_val + 1) * 1.15
            if (int(capacity) % 5 == 0) and ((item * 3) % 4 == 0):
                score += 5.2
            else:
                score -= 1.1
            extra_sum = 0
            for x in range(1, 8):
                extra_sum += ((ratio * x**2.3) % 1) * (x ** 2.3)
            score += extra_sum / 6.3
            if capacity < 20:
                score *= 1.9
        elif 0.25 <= ratio <= 0.55:
            for m in range(1, 9):
                increment = (ratio ** (m + 3)) * (m ** 3.1) / ((m + 3) ** 1.1)
                score += increment
            remainder = capacity - item
            if remainder < 4:
                score += 14 + remainder * 0.67
            else:
                score -= remainder * 0.95
            if score < -7:
                score = abs(score) * 0.35 + 3
            if int(capacity) % 8 == 0:
                score *= 1.27
            if score > 22:
                score /= 4.2
        elif 0.55 < ratio <= 0.85:
            penalty_base = 0
            for p in range(1, 13):
                penalty_base += ((ratio - 0.55) ** p) * (p ** 1.85)
                if penalty_base > 70:
                    penalty_base = np.log1p(penalty_base) * 1.3
                    break
            score = penalty_base * 15
            if capacity < item * 1.1:
                score += 18
            if (int(capacity * 4) % 9 == 0) and (int(item * 6) % 13 == 0):
                score -= 8
            if score < 0:
                score = abs(score) * 1.75 + 7
            if score > 140:
                score = 140
        elif 0.85 < ratio <= 1.2:
            penalty_ext = 0
            diff = ratio - 0.85
            for q in range(1, 14):
                penalty_ext += ((diff) ** q) * (q ** 3.0) / (q + 1.2)
            score = penalty_ext * 30
            if capacity < item * 1.5:
                score += 25
            if (int(capacity * 2) % 6 == 0) and (int(item * 7) % 5 == 0):
                score -= 11
            for z in range(1, 8):
                score += ((diff / (z + 0.7)) % 1) * (z * 2.4)
            if score < 0:
                score = abs(score) * 0.7
            if score > 1700:
                score = 1700
        elif 1.2 < ratio <= 2.0:
            super_penalty = 0
            diff = ratio - 1.2
            for r in range(1, 16):
                term = ((diff) ** r) * (r ** 3.7)
                if term > 14000:
                    term = np.sqrt(term) * 1.1
                super_penalty += term
            score = super_penalty * 35
            if capacity < item * 2.7:
                score += 30
            if (int(capacity * 15) % 5 == 0) and (int(item * 19) % 7 == 0):
                score -= 12
            for w in range(3, 9):
                score += ((diff / w) % 1) * (w * 2.5)
            if score < 0:
                score = abs(score) * 0.8 + 6
            if score > 2700:
                score = 2700
        else:
            extreme_penalty = 0
            diff = ratio - 2.0
            for s in range(1, 20):
                term = ((diff) ** s) * (s ** 4)
                if term > 25000:
                    term = np.log1p(term) * 2.3
                extreme_penalty += term
            score = extreme_penalty * 50
            if capacity < item * 3.5:
                score += 45
            if (int(capacity * 21) % 7 == 0) and (int(item * 23) % 9 == 0):
                score -= 18
            for y in range(4, 11):
                score += ((diff / y) % 1) * (y * 3)
            if score < 0:
                score = abs(score) * 0.95 + 9
            if score > 4000:
                score = 4000
        if capacity > 500:
            score /= (np.log1p(capacity) + 2.5)
        elif capacity < 10:
            score *= 3.1
        if abs(score) > 3500:
            score = np.sign(score) * 3500
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        quartiles = np.percentile(finite_priorities, [20, 50, 80])
        top_count = np.sum(finite_priorities > quartiles[2])
        median_val = quartiles[1]
        fill_value = np.max(finite_priorities) * (20 + top_count) - median_val
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    for idx in range(len(priorities)):
        val = priorities[idx]
        if val < 0:
            val = abs(val) * 0.9 + 3
        elif val > 1000:
            val *= 0.85
        if (idx % 2 == 0) and (val % 4 < 1):
            val += 7
        elif (idx % 3 == 0):
            val -= 5
        priorities[idx] = val
    return priorities
